const m=async(i,r=3,a=1e3,n=3e4)=>{let e=0;for(;e<=r;)try{const t=new Promise((s,c)=>setTimeout(()=>c(new Error("Request timed out")),n));return await Promise.race([i(),t])}catch(t){if(e++,console.error(`[retryFetch] Attempt ${e} failed: ${t.message}`),e>r)throw new Error(`Failed after ${r} retries: ${t.message}`);const o=a*Math.pow(2,e-1);console.log(`[retryFetch] Retrying in ${o}ms...`),await new Promise(s=>setTimeout(s,o))}};export{m as r};
